module top_module(
	intrIn, intr,
	ack, clk, rst
);input intrIn;
	output intr;
	input ack;
	input clk, rst;

	reg intr_r;

	always @(posedge clk) begin
		if (rst) begin
			intr_r <= 1'b0;
		end
		else if (ack) begin
			intr_r <= 1'b0;
		end
		else begin
			intr_r <= intr_r | intrIn;
		end
	end 

	wire inv_intr_reg = intr_r;
	assign intr = inv_intr_reg;endmodule
